#!/usr/bin/env python3
"""
show_services enviaba menos fotos de las esperadas (ej. 3 de 6
servicios activos con foto). Posible causa: rate limit de WhatsApp
Cloud API al mandar varias imagenes muy seguido. Ahora:

  - Se agrega una pausa de 400ms entre cada imagen enviada.
  - Se loguea cuantos servicios totales / con foto se detectaron
    ('[whatsapp-bot] show_services: N servicios totales, M con foto').
  - Si el envio de una imagen falla, se loguea el mensaje de error
    real (antes solo se logueaba el objeto Error completo).

Tambien incluye el fix anterior (enviar texto con los servicios
sin foto, y la lista de servicios autoritativa).

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_whatsapp_bot_show_services_fix.py
"""

import base64
from pathlib import Path

WHATSAPP_BOT_B64 = """"""

def main():
    p = Path("src/lib/whatsappBot.ts")
    p.write_bytes(base64.b64decode(WHATSAPP_BOT_B64))
    print(f"escrito: {p} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Bot de WhatsApp: pausa entre fotos de servicios + logs detallados'")
    print("  git push")

if __name__ == "__main__":
    main()